// ── LEAD SCORING ENGINE ──────────────────────────────────────────
const lead = $input.first().json;

let score = 0;
let scoreNotes = [];

// Timeline scoring
const timeline = (lead.timeline || '').toLowerCase();
if (timeline.includes('asap') || timeline.includes('immediately') || timeline.includes('urgent')) {
  score += 40;
  scoreNotes.push('ASAP timeline (+40)');
} else if (timeline.includes('month') || timeline.includes('soon')) {
  score += 25;
  scoreNotes.push('Short timeline (+25)');
} else if (timeline.includes('1-3') || timeline.includes('few months')) {
  score += 10;
  scoreNotes.push('Medium timeline (+10)');
} else {
  score += 0;
  scoreNotes.push('No timeline / just browsing (+0)');
}

// Service scoring
const service = (lead.service || '').toLowerCase();
if (service.includes('hurricane') || service.includes('impact')) {
  score += 30;
  scoreNotes.push('Hurricane windows — high value (+30)');
} else if (service.includes('full') || service.includes('whole') || service.includes('all')) {
  score += 30;
  scoreNotes.push('Full home replacement — high value (+30)');
} else if (service.includes('energy') || service.includes('efficient')) {
  score += 20;
  scoreNotes.push('Energy efficient — medium value (+20)');
} else if (service.includes('commercial')) {
  score += 25;
  scoreNotes.push('Commercial — high value (+25)');
} else if (service.includes('single') || service.includes('one window')) {
  score += 10;
  scoreNotes.push('Single window — lower value (+10)');
} else if (service.includes('repair')) {
  score += 5;
  scoreNotes.push('Repair — low value (+5)');
} else {
  score += 15;
  scoreNotes.push('Service unclear (+15)');
}

// Contact info completeness
if (lead.phone && lead.phone.length > 7) {
  score += 15;
  scoreNotes.push('Has phone (+15)');
}
if (lead.email && lead.email.includes('@')) {
  score += 10;
  scoreNotes.push('Has email (+10)');
}
if (lead.address && lead.address.length > 3) {
  score += 5;
  scoreNotes.push('Has address (+5)');
}

// Source scoring
const source = (lead.source || '').toLowerCase();
if (source === 'chatbot') {
  score += 5;
  scoreNotes.push('Chatbot lead — self-qualified (+5)');
} else if (source === 'form') {
  score += 5;
  scoreNotes.push('Form submission (+5)');
}

// Determine rating
let rating;
if (score >= 70) rating = 'HOT';
else if (score >= 40) rating = 'WARM';
else rating = 'COLD';

// Format timestamp
const now = new Date();
const timestamp = now.toLocaleString('en-US', { timeZone: 'America/New_York' });

return [{
  json: {
    ...lead,
    score,
    rating,
    scoreNotes: scoreNotes.join(' | '),
    timestamp,
    rowData: [
      timestamp,
      lead.name || '',
      lead.phone || '',
      lead.email || '',
      lead.address || lead.city || '',
      lead.service || '',
      lead.timeline || '',
      lead.source || 'website',
      lead.notes || '',
      score,
      rating,
      '', // Follow-up status (empty — filled by human)
      '', // Call notes (empty — filled by human)
      rating  // For conditional formatting column N
    ]
  }
}];

// Build Google Sheets row array
const d = $input.first().json;
return [{ json: { values: [d.rowData] } }];
